from sympy import Symbol, Integer, Add, Basic
from sympy.core._print_helpers import Printable
from sympy.core.expr import Expr, AtomicExpr
from sympy.logic.boolalg import Boolean
for cls in [Printable, Basic, Expr, AtomicExpr, Boolean, Symbol, Integer, Add]:
    x = None
    try:
        if cls is Symbol: x=cls('s')
        elif cls is Integer: x=cls(1)
        elif cls is Add: x=cls(Symbol('x'), Symbol('y'))
        elif cls in (Basic, Expr, AtomicExpr, Boolean): x=cls()
        else: x=cls()
        print(cls.__name__, cls.__dict__.get('__slots__', '<none>'), hasattr(x,'__dict__'), getattr(x,'__dict__', None), cls.__mro__)
    except Exception as e: print(cls.__name__, type(e), e)
PY"

